#!/usr/bin/env node
import { createHash } from 'node:crypto'
import { mkdir, readFile, writeFile } from 'node:fs/promises'
import { dirname, relative, resolve } from 'node:path'
import { fileURLToPath } from 'node:url'
import { build } from 'vite'

const scriptPath = fileURLToPath(import.meta.url)
const appRoot = resolve(dirname(scriptPath), '..')
const repoRoot = resolve(appRoot, '../..')
const outputPath = resolve(repoRoot, 'packages/backend/src/cloudflare/email-worker.generated.ts')
const checkOnly = process.argv.includes('--check')

const code = await bundleWorker()
const sha256 = createHash('sha256').update(code).digest('hex')
const generated = [
  '// Generated by apps/cloudflare-email-worker/scripts/generate-backend-bundle.mjs.',
  '// Source: apps/cloudflare-email-worker/src/index.js',
  '// Do not edit manually. Run `corepack pnpm --filter agent-mail-cloudflare-worker run generate:backend-bundle`.',
  '',
  'export const AGENT_MAIL_CLOUDFLARE_EMAIL_WORKER_SCRIPT_SHA256 =',
  `  '${sha256}' as const`,
  '',
  '// prettier-ignore',
  `export const AGENT_MAIL_CLOUDFLARE_EMAIL_WORKER_SCRIPT = ${stringLiteral(code)} as const`,
  ''
].join('\n')

if (checkOnly) {
  const existing = await readFile(outputPath, 'utf8').catch(() => '')
  if (existing !== generated) {
    const output = relative(repoRoot, outputPath)
    throw new Error(`${output} is stale. Regenerate the checked-in Worker bundle.`)
  }
  process.stdout.write(`${relative(repoRoot, outputPath)} is up to date\n`)
} else {
  await mkdir(dirname(outputPath), { recursive: true })
  await writeFile(outputPath, generated)
  process.stdout.write(`wrote ${relative(repoRoot, outputPath)} (${code.length} bytes, sha256 ${sha256})\n`)
}

async function bundleWorker() {
  const result = await build({
    root: appRoot,
    configFile: resolve(appRoot, 'vite.config.js'),
    logLevel: 'silent',
    build: {
      emptyOutDir: false,
      minify: true,
      sourcemap: false,
      write: false
    }
  })
  const outputs = Array.isArray(result) ? result.flatMap((item) => item.output) : result.output
  const chunks = outputs.filter((item) => item.type === 'chunk')
  if (chunks.length !== 1) {
    throw new Error(`Expected one bundled Worker chunk, received ${chunks.length}`)
  }
  const code = chunks[0].code.trimEnd() + '\n'
  if (/^\s*import\s/u.test(code) || /\n\s*import\s/u.test(code)) {
    throw new Error('Bundled Worker must not contain static import statements')
  }
  return code
}

function stringLiteral(value) {
  return JSON.stringify(value)
    .replace(/\u2028/gu, '\\u2028')
    .replace(/\u2029/gu, '\\u2029')
}
